#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — blog expansion installer (4 new posts: Calgary basement
# development cost + 3 vehicle-owner posts — windshield rock-chip repair,
# winter tires, winterize-your-vehicle). Frontend only; no DB changes.
# This resets to the published origin/main first, so it is a full superset —
# running it delivers everything already live PLUS the new blog posts.

TARGET="$HOME/Desktop/freddy-fixit"
if [ ! -d "$TARGET/.git" ]; then echo "❌ $TARGET is not a git repo"; exit 1; fi
cd "$TARGET"
echo "→ Syncing to the published version (discards any half-applied local state)"
git fetch origin --quiet || true
git reset --hard origin/main --quiet
rm -f .github/workflows/typecheck.yml
echo "→ Writing files into $TARGET"

write_file() {  # write_file <destpath> ; base64 body on stdin until marker
  local dest="$1"
  mkdir -p "$(dirname "$dest")"
  base64 --decode > "$dest"
}

echo "  • src/pages/Blog.tsx"
write_file 'src/pages/Blog.tsx' <<'B64_0'
